// Settings Screen Components Contract
// Files: src/screens/SettingsScreen.tsx, src/components/settings/TimezoneSelector.tsx,
//        src/components/settings/WeekStartSelector.tsx, src/components/settings/GoalDefaults.tsx,
//        src/components/settings/AccountSection.tsx

// Import from '@/screens'
export function SettingsScreen(): React.ReactElement;

// Import from '@/components/settings'
export interface TimezoneSelectorProps {
  value: string;
  onChange: (timezone: string) => void;
  disabled?: boolean;
  loading?: boolean;
  style?: ViewStyle;
}
export function TimezoneSelector(props: TimezoneSelectorProps): React.ReactElement;

export interface WeekStartSelectorProps {
  value: number;
  onChange: (day: number) => void;
  disabled?: boolean;
  loading?: boolean;
  style?: ViewStyle;
}
export function WeekStartSelector(props: WeekStartSelectorProps): React.ReactElement;

export interface GoalDefaultsProps {
  style?: ViewStyle;
}
export function GoalDefaults(props: GoalDefaultsProps): React.ReactElement;

export interface AccountSectionProps {
  email: string | null;
  name: string | null;
  avatarUrl?: string | null;
  onSignOut: () => Promise<void>;
  style?: ViewStyle;
}
export function AccountSection(props: AccountSectionProps): React.ReactElement;

// Behavior notes:
// - SettingsScreen integrates useUserSettings hook for fetching/updating profile
// - TimezoneSelector is a searchable modal with 70+ IANA timezones, shows UTC offset
// - WeekStartSelector shows all 7 days as selectable chips (0=Sunday to 6=Saturday)
// - GoalDefaults persists default monthly goal hours to local storage
// - AccountSection shows avatar (or initials fallback), email, name, and sign out button
// - All settings changes call useUpdateUserSettings mutation
// - App version display at bottom from expo-constants
// - Pull-to-refresh support on settings list
